class Solution:
    def sortVowels(self, s: str) -> str:
        vowels = set("aeiouAEIOU")
        vowel_list = sorted((ch for ch in s if ch in vowels))
        vi = 0
        out = []
        for ch in s:
            if ch in vowels:
                out.append(vowel_list[vi])
                vi += 1
            else:
                out.append(ch)
        return "".join(out)
